// // This module implements a 2-to-4 decoder with an enable signal. When the enable signal is 1, all outputs are 0. When the enable signal is 0, the output is determined by the 2-bit input.
module decoder_2_to_4(A, EN, Y);
input [1:0] A;
input EN;
output reg [3:0] Y;

always @(*) begin
    if (EN) begin
        case (A)
            2'b00: Y = 4'b0001;
            2'b01: Y = 4'b0010;
            2'b10: Y = 4'b0100;
            2'b11: Y = 4'b1000;
            default: Y = 4'b0000;
        endcase
    end else begin
        Y = 4'b0000;
    end
end

endmodule
